import React from "react";

export default function Navbar({ user, logout, currentPage, setCurrentPage }) {
  const navItems = [
    { id: "home", label: "Home", icon: "🏠" },
    { id: "academic", label: "Academic", icon: "📚" },
    { id: "food", label: "Food", icon: "🍽️" },
    { id: "laundry", label: "Laundry", icon: "🧺" },
    { id: "complaint", label: "Complaint", icon: "📋" },
  ];

  return (
    <nav className="navbar">
      <div className="max-w-7xl mx-auto px-4 py-4 flex items-center justify-between">
        <div className="flex items-center gap-8">
          <div className="text-2xl font-bold bg-gradient-to-r from-blue-600 to-blue-500 bg-clip-text text-transparent">
            UniEase
          </div>

          <div className="hidden md:flex gap-6">
            {navItems.map((item) => (
              <button
                key={item.id}
                onClick={() => setCurrentPage(item.id)}
                className={`flex items-center gap-2 px-3 py-2 rounded-lg transition-all ${
                  currentPage === item.id
                    ? "tab-active bg-blue-50"
                    : "tab-inactive hover:bg-slate-50"
                }`}
              >
                <span>{item.icon}</span>
                <span className="text-sm font-medium">{item.label}</span>
              </button>
            ))}
          </div>
        </div>

        <div className="flex items-center gap-4">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-gradient-to-br from-blue-400 to-blue-600 flex items-center justify-center text-white font-bold">
              {user?.name?.[0] || "S"}
            </div>
            <div className="hidden sm:block">
              <p className="text-sm font-semibold text-slate-900">{user?.name}</p>
              <p className="text-xs text-slate-600">Student</p>
            </div>
          </div>

          <button
            onClick={logout}
            className="px-4 py-2 bg-red-500 hover:bg-red-600 text-white rounded-lg font-semibold transition-all duration-300 text-sm"
          >
            Logout
          </button>
        </div>
      </div>
    </nav>
  );
}
